// firebase-messaging-sw.js
// Handles background push messages from Firebase Cloud Messaging.
// Coexists with the workbox SW generated by next-pwa (different scopes/names).

importScripts('https://www.gstatic.com/firebasejs/10.12.0/firebase-app-compat.js');
importScripts('https://www.gstatic.com/firebasejs/10.12.0/firebase-messaging-compat.js');

// Config is fetched from our API route on install (env vars can't be read in a SW)
self.addEventListener('install', (event) => {
  event.waitUntil(
    fetch('/api/sw-config')
      .then((r) => r.text())
      .then((js) => {
        // eslint-disable-next-line no-eval
        self.eval(js); // sets self.__FIREBASE_CONFIG__
        initFirebase();
      })
      .catch((e) => console.error('[FCM SW] Failed to load config:', e))
  );
});

function initFirebase() {
  if (!self.__FIREBASE_CONFIG__) return;

  // Avoid double-init if the SW reloads
  if (!firebase.apps || firebase.apps.length === 0) {
    firebase.initializeApp(self.__FIREBASE_CONFIG__);
  }

  const messaging = firebase.messaging();

  // Background push handler — fires when app tab is hidden / closed
  messaging.onBackgroundMessage((payload) => {
    console.log('[FCM SW] Background message:', payload);
    const { title, body, icon, url } = payload.data || {};

    self.registration.showNotification(title || 'VitaMyStory', {
      body: body || 'Someone interacted with your story.',
      icon: icon || '/icon-192x192.png',
      badge: '/icon-192x192.png',
      data: { url: url || '/' },
      vibrate: [200, 100, 200],
    });
  });
}

// Tap notification → open app at the right URL
self.addEventListener('notificationclick', (event) => {
  event.notification.close();
  const url = event.notification.data?.url || '/';
  event.waitUntil(
    clients
      .matchAll({ type: 'window', includeUncontrolled: true })
      .then((list) => {
        const existing = list.find((c) => c.url === url);
        if (existing && 'focus' in existing) return existing.focus();
        if (clients.openWindow) return clients.openWindow(url);
      })
  );
});
